 1→import { useFocusEffect } from '@react-navigation/native';
 2→import { useCallback, useEffect, useRef, useState } from 'react';
 3→import type { WebViewProps } from '../../atomic/templates/WebViewScreen/Models';
 4→import { useScreenViewTracking } from '../../hooks/tracking';
 5→import { useAirlineMiles } from '../../services';
 6→import type {
 7→  AirlineMilesMarketplaceScreenProps,
 8→  UseAirlineMilesMarketplaceReturn,
 9→} from './Models';
10→
11→export function useAirlineMilesMarketplace(
12→  props: AirlineMilesMarketplaceScreenProps,
13→): UseAirlineMilesMarketplaceReturn {
14→  const { navigation, route } = props;
15→  useScreenViewTracking({
16→    route,
17→    title: 'Milhas Aéreas',
18→  });
19→
20→  const [isWebViewError, setIsWebViewError] = useState(false);
21→  const webViewRef = useRef<WebViewProps>(null);
22→
23→  const { redirectURL, isLoading, isError, fetchAirlineMilesToken, reset } =
24→    useAirlineMiles();
25→
26→  useFocusEffect(
27→    useCallback(() => {
28→      let isActive = true;
29→
30→      const fetchData = async () => {
31→        if (isActive) {
32→          setIsWebViewError(false);
33→        }
34→        await fetchAirlineMilesToken();
35→      };
36→
37→      fetchData();
38→
39→      return () => {
40→        isActive = false;
41→      };
42→    }, [fetchAirlineMilesToken]),
43→  );
44→
45→  useEffect(() => {
46→    return () => {
47→      reset();
48→    };
49→  }, [reset]);
50→
51→  const handleGoBack = useCallback(() => {
52→    navigation.goBack();
53→  }, [navigation]);
54→
55→  const handleWebViewError = useCallback(() => {
56→    setIsWebViewError(true);
57→  }, []);
58→
59→  const handleRetry = useCallback(() => {
60→    setIsWebViewError(false);
61→    fetchAirlineMilesToken();
62→  }, [fetchAirlineMilesToken]);
63→
64→  return {
65→    isWebViewError,
66→    redirectURL,
67→    isLoading,
68→    isError,
69→    webViewRef,
70→    handleGoBack,
71→    handleWebViewError,
72→    handleRetry,
73→  };
74→}
75→
76→export { default } from './view';
77→

 1→import React from 'react';
 2→import AnimationArrows from '../../atomic/atoms/AnimationArrows';
 3→import ApiError from '../../atomic/organisms/ApiError';
 4→import BasicScreen from '../../atomic/templates/BasicScreen';
 5→import { WebViewScreen } from '../../atomic/templates/WebViewScreen';
 6→import { useAirlineMilesMarketplace } from './index';
 7→import type { AirlineMilesMarketplaceScreenProps } from './Models';
 8→
 9→const SCREEN_TITLE = 'Milhas Aéreas';
10→
11→export default function AirlineMilesMarketplaceScreen(
12→  props: AirlineMilesMarketplaceScreenProps,
13→) {
14→  const {
15→    isWebViewError,
16→    redirectURL,
17→    isLoading,
18→    isError,
19→    webViewRef,
20→    handleGoBack,
21→    handleWebViewError,
22→    handleRetry,
23→  } = useAirlineMilesMarketplace(props);
24→
25→  if (isLoading) {
26→    return <AnimationArrows />;
27→  }
28→
29→  if (isError || !redirectURL || isWebViewError) {
30→    return (
31→      <BasicScreen
32→        leftIconOnPress={handleGoBack}
33→        title={SCREEN_TITLE}
34→        errorButtonOnPress={handleRetry}
35→      >
36→        <ApiError onPress={handleRetry} />
37→      </BasicScreen>
38→    );
39→  }
40→
41→  return (
42→    <WebViewScreen
43→      uri={redirectURL}
44→      title={SCREEN_TITLE}
45→      webViewRef={webViewRef}
46→      onBackPress={handleGoBack}
47→      onError={handleWebViewError}
48→      onRetry={handleRetry}
49→    />
50→  );
51→}
