 69→const ExtractRewardProgram: FC<ExtractRewardProgramProps> = ({
 70→  route,
 71→  navigation,
 72→}) => {
 73→  const {
 74→    hasError,
 75→    handleGoBack,
 76→    pointsAvailable,
 77→    isLoadingExtract,
 78→    isLoadingMore,
 79→    isLoadingBalance,
 80→    isRefreshing,
 81→    transactionsData,
 82→    searchText,
 83→    activeFiltersCount,
 84→    transactionsEmptyMessage,
 85→    shouldShowTransactionsList,
 86→    filterGroups,
 87→    initialFilters,
 88→    modalizeRefInfo,
 89→    modalizeRefFilters,
 90→    handleSearchChange,
 91→    handleRefresh,
 92→    handleError,
 93→    handleScroll,
 94→    handleIconInfoPress,
 95→    handleFilterIconPress,
 96→    handleApplyFilters,
 97→    handleTabChange,
 98→    handleSearchPressIn,
 99→  } = useExtractRewardProgramScreen({
100→    route,
