211→        });
212→      });
213→
214→      marketplaceContent = {
215→        orderNumber: enrichedTransaction.id,
216→        status: enrichedTransaction.status,
217→        statusColor: enrichedTransaction.status
218→          ? STATUS_COLORS[enrichedTransaction.status] || 'neutral'
219→          : undefined,
220→        paymentType: firstPayment
221→          ? getPaymentTypeLabel(firstPayment.paymentType)
222→          : undefined,
223→        shippingValuePoints:
224→          marketplace.shippingValuePoints !== undefined &&
225→          marketplace.shippingValuePoints !== null
226→            ? getFormattedPointsValueForMarketplace(
227→                marketplace.shippingValuePoints,
228→              )
229→            : undefined,
230→        valuePoints:
231→          marketplace.valuePoints !== undefined &&
232→          marketplace.valuePoints !== null
233→            ? getFormattedPointsValueForMarketplace(marketplace.valuePoints)
234→            : undefined,
235→        vendorName: vendorName || undefined,
236→        items,
237→      };
238→    }
239→
240→    return {
241→      cardTitle,
242→      formattedPointsValue,
243→      highlightText,
244→      formattedCurrencyValue,
245→      marketplaceContent,
246→      showOrderNumber: !isMarketplace,
247→      showStatus: !isMarketplace,
248→      showValue: !isMarketplace,
249→    };
250→    // eslint-disable-next-line react-hooks/exhaustive-deps
251→  }, [
252→    transaction,
253→    passedType,
254→    passedIcon,
255→    passedStatus,
256→    passedOrigination,
257→  ]);
258→
259→  return (
260→    <MyOrdersDetailView
261→      handleGoBack={handleGoBack}
262→      transaction={enrichedTransaction}
263→      modalizeRef={modalizeRef}
264→      modalizeRefInfo={modalizeRefInfo}
265→      handleOpenReportProblem={handleOpenReportProblem}
266→      handleCloseReportProblem={handleCloseReportProblem}
267→      handleOpenInfo={handleOpenInfo}
268→      handleCloseInfo={handleCloseInfo}
269→      isLoading={isLoading}
270→      hasError={hasError}
271→      handleRetry={handleRetry}
272→      isCashback={isCashback}
273→      cardTitle={processedData.cardTitle}
274→      formattedPointsValue={processedData.formattedPointsValue}
275→      highlightText={processedData.highlightText}
276→      formattedCurrencyValue={processedData.formattedCurrencyValue}
277→      marketplaceContent={processedData.marketplaceContent}
278→      showOrderNumber={processedData.showOrderNumber}
279→      showStatus={processedData.showStatus}
